import recipes from "../../recipes";

const Menu = () => {
    return (
        <>
            <div className="menu">
                <div className="menu-header">
                    <h2>This weeks specials</h2>
                    <button>Order Menu</button>
                </div>
            </div>

            <div>
                {
                    recipes.map(recipe => <div key={recipe.id}>
                        <img src={require(`../../images/${recipe.image}`)} alt="" />
                        <div>
                            <h5>{recipe.title}</h5>
                            <p>{recipe.price}</p>
                        </div>
                    </div>)
                }
            </div>
        </>
    )
}

export default Menu;
